module RefModule(
input	[2:0]codes,
output	zero,
output	double,
output	negation
);
wire	A;
  assign	zero=(A&BC)|(nA&nBnC);
wire	B;
  assign	negation=A&nBanC;
wire	C;
  assign	double=(nBnC&A)|(BC&nA);
wire	nB,nC,nA;
  assign	nBanC=nB|nC;
  assign	nBnC=nB&nC;
  assign	BC=B&C;
wire	BC;
  assign	nA=~A;
wire	nBnC;
  assign	nC=~C;
wire	nBanC;
  assign	nB=~B;
  assign	C=codes[0];
  assign	B=codes[1];
  assign	A=codes[2];
endmodule
